<template>
  <div>
    <el-row :gutter="40" class="panel-group" style="margin: 0px 0px 0px 0px">
      <el-col v-for="(collab,index) in collabInfo" :key="index" :xs="12" :sm="12" :lg="6" class="card-panel-col">
        <colab-card-usage
          :automation-usage-info="collab"/>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import CountTo from 'vue-count-to'
import ColabCardUsage from './ColabCardUsage'
import { mapGetters, mapActions } from 'vuex'

export default {
  components: {
    ColabCardUsage,
    CountTo
  },
  data: function() {
    return {
      green: 0,
      yellow: 0
    }
  },
  computed: {
    ...mapGetters('automationUsage', ['collabInfo'])
  },
  mounted() {
    this.getCollabInfo()
  },
  methods: {
    ...mapActions('automationUsage', ['getCollabInfo']),
    convertToColor(value) {
      // console.log(value)
      if (value >= this.green) {
        return '#5cb85c'
      } else if (value >= this.yellow) {
        return '#f0ad4e'
      } else {
        return '#d9534f'
      }
    }
  }
}
</script>

